var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"크악!","JPN":"ぐあっ！","ENG":"Wah!","TWN":"啊啊！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"이렇게...... 이렇게 예언자님의 뜻을 이루지 못하고 죽다니......!","JPN":"こんな……預言者様の志を遂げずに死ぬなんて……！","ENG":"I can't... I can't die without realizing the Prophet's will... like this!","TWN":"怎麼會……還沒完成預言者大人的意志，我居然就要這樣死去了……！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"마젤란의 형제들이여! 부디 내 뒤를 이어 주길 바란다......!","JPN":"マジェランの兄弟たちよ！　どうか私の後を継いでほしい……！","ENG":"Brothers of Magellan, I leave everything else to you!","TWN":"麥哲倫的弟兄們！請跟隨我的腳步……！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"크윽......","JPN":"くっ……","ENG":"Ugh...","TWN":"唔……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"칼날에 스치지도 않았는데 죽다니 신기하네요. 그런 기술은 배운 적 없을 텐데 말이죠.","JPN":"刃に触れてないのに死ぬなんて不思議ですね。\\nそんな技術を学んだ覚えはありませんが。","ENG":"My sword didn't even graze you, and you dropped dead at once. Is it some kind of skill you learned from past experiences?","TWN":"刀子都沒碰到就要死了，真是太神奇了，你們應該沒有這種技能吧。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"무척 조화롭지 않은 일이에요. 그렇지 않나요, 이디스?","JPN":"とても不調和なことです。そうではないですか、イーディス？","ENG":"This is not harmonious at all. Don't you agree, Edith?","TWN":"這太不合理了。對吧，伊蒂絲？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐아암...... 주르, 고춧가루 폭탄 발사해.","JPN":"ふわぁ～J.O.U.R.、唐辛子爆弾を発射して。","ENG":"*Yawn*... J.O.U.R., fire red pepper bombs.","TWN":"呼啊啊……朱爾，發射辣椒粉炸彈。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"쿨럭! 쿨럭! 이런 피도 눈물도 없는 놈들! 쿨럭......!","JPN":"ゲホッ、ゲホッ！　この鬼！　ゲホッ……！","ENG":"*Cough, cough!* You meanies! *Cough!*","TWN":"咳咳！咳咳！你們這些沒血沒淚的傢伙！咳咳……！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"회장님! 이디스 언니! 경찰 아저씨들이 도착했어요!","JPN":"会長！　イーディスお姉さん！　警察のおじさんたちが到着しました！","ENG":"Miss President! Edith! The police are here!","TWN":"會長！伊蒂絲姐姐！警察叔叔們到了！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"예언자님께서는 꼭 돌아오실 것이다!","JPN":"預言者様は必ずお戻りになるはずだ！","ENG":"The Prophet will return, no matter what!","TWN":"預言者大人一定會回來的！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"오오! 우리는 마젤란의 형제들~","JPN":"おぉ！　私たちはマジェランの兄弟たち～！","ENG":"Ooooh, we're the brethren of Magellan, chosen by the Prophecy...","TWN":"喔喔！我們是麥哲倫的弟兄們！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"신세계에서 살아갈~ 예언의 신인류~","JPN":"新世界で生きていく～予言の新人類～！","ENG":"'Tis the New World we shall dwell in, for we're the New Humanity...","TWN":"活在新世界～預言的新人類～"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자, 자. 노래는 노래방 가서 부르시고 얌전히 한 줄로 서서 호송차에 타세요.","JPN":"さあさあ、あとはカラオケで歌って。\\n今は大人しく一列に並んでパトカーに乗ってください。","ENG":"Alright, alright! This is not karaoke time. Just stand in line and get in the police van.","TWN":"好啦，好啦，要唱就到卡拉OK再唱啦。乖乖排成一列，坐上押送車吧。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"안 그러면 무서운 언니한테 혼날 줄 알아요.","JPN":"そうしないと、怖いお姉さんに怒られますよ。","ENG":"Or this scary lady here will get really nasty.","TWN":"不然會被可怕的姐姐教訓一頓喔。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"이런 식으로 탄압한다고 우리 마젤란 예언회가 주저앉을 것 같으냐!","JPN":"こんなふうに弾圧したところで、我々マジェラン予言会が崩れると思うのか！","ENG":"This is persecution. Magellan's Prediction Society will not be oppressed!","TWN":"我們麥哲倫預言會絕對不會屈服於這種迫害的。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"예언자님께서 은빛 구름을 타고 다시 오실 것이다! 그때 가서 후회하지나 마라!","JPN":"預言者様が銀色の雲に乗って再び降臨されるはずだ！\\nそのときに後悔しても遅い！","ENG":"The Prophet will return on a silver cloud! By then, it'll be too late for you to regret!","TWN":"預言者大人會駕著銀光雲彩回來的！到時候你們可別後悔！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자 주제에 뭘 잘했다고 큰소리야? 은빛 수갑으로 한 번 맞아 볼래?!","JPN":"犯罪者のくせに何を偉そうに言ってるの？\\n銀色の手錠で殴られたい？","ENG":"Shut up, you stupid criminals, before I mark you with these silver handcuffs.","TWN":"你一個罪犯還敢講這種話？要不要先嘗嘗銀光手銬的滋味？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BAG","text":{"KOREA":"......겨, 경찰이 시민을 협박해도 되는 겁니까?! 고소합니다?! 고소할 거라고요!","JPN":"……け、警察が市民を脅かしていいんですか？\\n訴えますよ！　訴えますから！","ENG":"Y-you're police. You can't threaten citizens like this! I'll sue you. I will sue YOU!","TWN":"……警、警察竟敢威脅市民？！我要告妳？！我要告妳喔！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_BAG","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥. 당신들 앞으로 올 고소장이나 걱정하시지.","JPN":"ふん。あなたたち宛の告訴状は心配じゃないのかしら？","ENG":"Pfft, you'll get sued before you can sue us.","TWN":"哼，你還是先擔心你即將收到的起訴書吧。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이야, 경정님 많이 변하셨네요.","JPN":"いやー、警視様もだいぶ丸くなりましたね。","ENG":"Wow! Major, you've changed a lot.","TWN":"哇，警正大人變了好多喔。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"평소 같았으면 이미 구급차가 추가로 몇 대 도착했어야 하는데.","JPN":"普段なら救急車を追加要請しなければならないのに。","ENG":"I was ready to call a few more ambulances.","TWN":"要是以前，這裡應該已經多了幾台救護車了。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"조, 조용히 해, 경위! 보는 사람들도 있는데 쓸데없는 소리할래?","JPN":"な、何を言ってるの、マエカワ警部補！\\nみんなが誤解するような無駄口を叩かないでくれる？","ENG":"B-be quiet, Lieutenant. There are eyes on us.","TWN":"安、安靜點，警衛！這麼多人在看，不要亂講話啦？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"크흠. 고마워요. 여러분의 협조로 범죄자들을 신속하게 검거할 수 있었습니다.","JPN":"こほん。ありがとう。皆さんの協力のおかげで\\n犯罪者たちを迅速に逮捕することができました。","ENG":"Kahem. Thank you, everyone. We couldn't have apprehended these criminals so quickly if it weren't for you.","TWN":"咳咳，謝謝你們。多虧有你們幫忙，我們才能這麼快就逮捕罪犯。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"흐, 흐흠. 심판의 방아쇠는 악인을 놓치지 않지. 당연한 결과다.","JPN":"ふ、ふん。審判の引き金は悪人を逃がさない。当然の結果だ。","ENG":"Hm, hm hm. This trigger of judgement never misses villains. This was expected.","TWN":"哼，哼哼，審判的扳機是絕不會放過一個壞人的，這是理所當然的結果。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"하지만 알렉산더가......","JPN":"でも、アレクサンダーが……","ENG":"But Alexander...","TWN":"但是亞歷山大……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"알렉산더? 혹시 학생이 기르던 애완동물인가요?","JPN":"アレクサンダー？　ひょっとして学生が飼ってたペットのことですか？","ENG":"Alexander? Is that the name of your pet animal?","TWN":"亞歷山大？是同學妳養的寵物嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"아뇨. 같은 동네 사는 할아버지의 자식 같은 강아지예요.","JPN":"いいえ。うちの街に住むおじいさんにとって、我が子同様の犬です。","ENG":"No, but it's the greengrocer in my neighborhood's dog.","TWN":"不，是我家附近的一位老爺爺，他非常疼愛的小狗。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그런데 저 사람들이 나쁜 짓을 하려는 데 써서......","JPN":"なのに、あの人たちが悪いことに利用して……","ENG":"And they used him to do bad things...","TWN":"但牠卻被那些壞人抓來做實驗了……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......그렇군요.","JPN":"……そうですか。","ENG":"I see.","TWN":"……原來如此。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"안타깝지만, 그 대신 저 범죄자들이 꼭 정당한 처벌을 받을 수 있게 해 드리겠습니다.","JPN":"残念ですが……その代わり、あの犯罪者たちが\\n必ず罪に見合う処罰を受けるようにします。","ENG":"I'm sorry to hear that. I'll make sure they'll get the punishment that they deserve.","TWN":"很遺憾，我們一定會讓那些罪犯受到應當的懲罰。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아, 여러분. 저쪽에서 혼자 있는 강아지를 찾았는데 혹시 뭔가 알고 있을까요?","JPN":"あ、皆さん。あそこで犬を一匹を見つけましたが何か知ってますか？","ENG":"Oh, guys. I found a puppy sitting alone over there. Do you know him by chance?","TWN":"啊，各位。我在那邊找到了一隻小狗，你們認識牠嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"알렉산더! 원래 모습으로 돌아왔구나!","JPN":"アレクサンダー！　元の姿に戻ったのね！","ENG":"Alexander! You're back to your old self!","TWN":"亞歷山大！你恢復原狀了！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아, 정말이네?!","JPN":"あ、本当だ！","ENG":"Oh, he is!","TWN":"哇，真的耶？！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"다행이야, 소림아! 우리가 열심히 놀아 줘서 원래대로 돌아왔나 봐!","JPN":"よかった、ミズキちゃん！　僕たちがいっぱい\\n一緒に遊んであげたからか、元に戻れたみたい！","ENG":"This is great, Sorim! He must have come back to normal because we played with him!","TWN":"太好了，蕭林！一定是我們常常陪牠玩，牠才能恢復原狀的！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"우으...... 하림 언니...... 숨 막혀......","JPN":"うう……ウサギ隊長……息苦しい……","ENG":"Ugh... Harim... I can't breathe...","TWN":"唔……夏琳姐姐……我不能呼吸了……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생들이 기뻐하는 모습을 보니 뿌듯하네요. 이디스도 그렇지 않나요?","JPN":"生徒が喜ぶ姿を見ると嬉しいですね。\\nイーディスもそうでしょう？","ENG":"I'm happy to see them so joyful. Aren't you, Edith?","TWN":"看到學生們高興的樣子，內心也會跟著高興起來呢。對吧，伊蒂絲？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"으응~ 잘됐네~","JPN":"うん～、よかったね～。","ENG":"Yes, I am.","TWN":"嗯～太好了～"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그런데 치료제로 알렉산더를 고쳐 줬단 얘기는 왜 안 하는 거야?","JPN":"ところで、治療剤でアレクサンダーを治してあげた話はなんでしないの？","ENG":"But are you not going to tell them that you used the cure on Alexander?","TWN":"但妳為什麼不告訴她們，是妳用治療藥讓亞歷山大恢復的？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"우리 학생들이 자처한 선행이잖아요. 괜한 부담을 주고 싶진 않아요.","JPN":"うちの生徒が自分たちで行った善行ですから。\\n余計な負担をかけたくないのです。","ENG":"Our students volunteered to save him. I don't want to spoil that.","TWN":"這是她們自發的善舉，我不想讓她們有負擔。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그리고 무엇보다, 스스로 해냈다는 성취감을 가지는 게 가장 뿌듯할 나이잖아요?","JPN":"そして何より、自分自身でやり遂げたという\\n達成感を得ることが一番嬉しい年ごろでしょう？","ENG":"Most of all, they're at the age when a sense of achievement can make a huge difference in their lives.","TWN":"而且在他們這個年紀，通過自己的努力完成一件事，不是最有成就感的嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미안해요. 치료제는 이디스가 찾아 준 건데, 그걸 내 멋대로 숨기려 해서.","JPN":"ごめんなさい。イーディスが治療剤を見つけてくれたのに、\\nそのことを勝手に隠したりして。","ENG":"I'm sorry if you wanted to tell them. After all, you're the one who found the cure for him.","TWN":"不過真是抱歉，治療藥明明是伊蒂絲找到的，我卻擅自隱瞞了下來。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"학생회장이 비밀로 하고 싶어하는 거라면 그렇게 해~","JPN":"生徒会長が秘密にしたいならそれでいいよ～。","ENG":"Don't be. I have no problem keeping it secret, if that's what you want.","TWN":"既然學生會長想保密，那就保密唄～"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"나야...... 흐아암...... 일찍 끝내고 싶은 것뿐이니까......","JPN":"私は……ふわぁ……早く終わらせたいだけなんだから……","ENG":"I'm okay... *Yawn*... so long as I can go back to sleep...","TWN":"我只想……哈啊……趕快了結這件事……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"하암...... 피곤해...... 이만 잘게......","JPN":"ふわぁ……疲れた……そろそろ寝る……","ENG":"*Yawn* ... So tired... Back to sleep now...","TWN":"哈啊……好睏喔……我先睡了……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 고생 많았어요, 이디스.","JPN":"はい。お疲れ様でした、イーディス。","ENG":"Yes, Edith. Thank you.","TWN":"好的，辛苦妳了，伊蒂絲。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"회장님, 이디스 언니!","JPN":"会長、イーディスお姉さん！","ENG":"Miss President! Edith!","TWN":"會長！伊蒂絲姐姐！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"고마워요. 덕분에 알렉산더랑 다른 동물 친구들을 구할 수 있었어요!","JPN":"ありがとうございます。おかげでアレクサンダーや他の動物たちを\\n救うことができました！","ENG":"Thank you. We saved Alexander and other animals because of you.","TWN":"謝謝你們，多虧你們幫忙，我們才能解救亞歷山大和其他動物朋友。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇지 않아요. 여러분이 나서 준 덕분에 가능했던 거죠.","JPN":"そんなことないです。皆さんが頑張ってくれたおかげです。","ENG":"No, thank you. It was because of you we could save them.","TWN":"不，這都是因為你們願意挺身而出，所以才能辦到的。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"앗, 알렉산더!","JPN":"あっ、アレクサンダー！","ENG":"Ah, Alexander!","TWN":"啊，亞歷山大！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아하하, 알렉산더가 고맙대요. 언니한테 안기고 싶나 봐요.","JPN":"あはは、アレクサンダーがありがとうって。\\nお姉さんに抱っこされたいみたいです。","ENG":"Hah hah hah. Alexander thanks you, too. I think he wants to give you a hug.","TWN":"哈哈哈，亞歷山大在跟妳說謝謝，牠想讓姐姐抱抱。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"음? 그래도 괜찮나요?","JPN":"おや？　そうしてもいいんですか？","ENG":"Mm? Do you think so?","TWN":"咦？這真的沒關係嗎？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"전 한 번도 동물을 안아 본 적이 없는데......","JPN":"私、一度も動物を抱っこしたことがないのですが……","ENG":"I've never held an animal before...","TWN":"我從來沒抱過動物……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"에이, 그러지 말고요.","JPN":"じゃあ、ぜひ抱いてみてください。","ENG":"Come on, try it.","TWN":"哎呀，別這樣說嘛。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"앗, 부드러워!","JPN":"あっ、柔らかい！","ENG":"Oh, so soft!","TWN":"哇，好軟喔！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이런 중독될 것 같은 복슬복슬함이라니...... 신선한 경험이네요.","JPN":"くせになりそうなこのモフモフ感……新鮮な経験ですね。","ENG":"His fur feels so soft to the touch, it's almost addictive. This is a refreshingly pleasant experience.","TWN":"這種會讓人中毒的毛茸茸觸感，好舒服啊……真是新奇的體驗呢。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"헤헤. 알렉산더도 회장님이 좋나 봐요.","JPN":"えへへ。アレクサンダーも会長が好きみたいです。","ENG":"Heh heh. I think Alexander likes you.","TWN":"嘿嘿，亞歷山大好像也很喜歡會長。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"확실히 사랑스러운 털뭉치네요. 가능하다면 계속 쓰다듬어 주고 싶을 정도예요.","JPN":"確かに、可愛らしいワンコですね。\\nできればずっと、なでなでしていたいぐらいです。","ENG":"He's definitely an adorable ball of fur. I think I could pet him for the rest of my life.","TWN":"確實是很可愛的小毛團呢。如果可以的話，會想要一直摸下去呢。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"자, 그러면 기념으로 다 같이 사진 찍어요!","JPN":"さあ、記念にみんなで写真を撮りましょう！","ENG":"Ooo, let's take a souvenir photo together!","TWN":"來，大家一起拍照留個紀念吧！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네? 이대로 말인가요?","JPN":"え？　このままでですか？","ENG":"Excuse me? Right now?","TWN":"什麼？就這樣拍？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 이렇게 찍으면 회장으로서 지켜야 할 위엄이......","JPN":"こんな姿を撮られると、会長としての威厳が……","ENG":"But with him in my arms, I wouldn't look as dignified as a President should...","TWN":"可是這樣拍的話，身為會長應該保持的威嚴就……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흠냐아...... 뭐 어때, 회장...... 가끔은 무게 잡지 않아도 되잖아......","JPN":"ふうん……まぁいいじゃない、会長……\\nたまには格好つけなくてもいいんじゃない……","ENG":"*Yawn*... Come on, you don't have to look serious all the time...","TWN":"哎……沒關係啦，會長……偶爾放鬆一下也不錯啊……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"전 좋아요, 호진 언니!","JPN":"僕はいいと思いますよ、マユミさん！","ENG":"I'm ready, Hojin!","TWN":"我很願意，鎬眞姐姐！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"보, 본관은 특수 임무를 맡고 있다. 얼굴이 노출되면 아, 안 되는데......","JPN":"ほ、本官は、特殊任務を任されている。\\n顔が写ったらダ、ダメだが……","ENG":"I-I'm on a special mission. I-I can't expose my face...","TWN":"本，本官正在執行特殊任務，不能露臉。不、不要啊……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"에이, 소림이도 부끄러워 말구!","JPN":"さあ、ミズキちゃんも入って！","ENG":"Come on, Sorim. Don't be shy!","TWN":"來，蕭林也不要害羞嘛！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하으으......","JPN":"はうぅ……","ENG":"Uggghh...","TWN":"哈啊……"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그럼 찍을게요!","JPN":"それじゃあ、撮りますね！","ENG":"Okay, here we go!","TWN":"那要拍囉！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"하나, 둘, 셋!","JPN":"はい、チーズ！","ENG":"Say cheese!","TWN":"一、二、三！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};